module asyn_fifo
#(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)
(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

reg [WIDTH-1:0] ram [0:DEPTH-1];
wire [ADDR_WIDTH-1:0] waddr, raddr;
wire [WIDTH-1:0] rdata_wire;

reg [ADDR_WIDTH:0] wptr, wptr_sync;
wire [ADDR_WIDTH-1:0] wbin, wgray;
wire wfull_wire;

reg [ADDR_WIDTH:0] rptr, rptr_sync;
wire [ADDR_WIDTH-1:0] rbin, rgray;
wire rempty_wire;

always @(posedge rclk or negedge wrstn) begin
    if (~wrstn) begin
        wptr_sync <= 0;
    end else begin
        wptr_sync <= wptr;
    end
end

always @(posedge wclk or negedge rrstn) begin
    if (~rrstn) begin
        rptr_sync <= 0;
    end else begin
        rptr_sync <= rptr;
    end
end

always @(posedge wclk or negedge wrstn) begin
    if (~wrstn) begin
        wptr <= 0;
        wfull <= 0;
    end else begin
        if (winc & ~wfull) begin
            ram[waddr] <= wdata;
            wptr <= wptr + 1;
        end
        wfull <= wfull_wire;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (~rrstn) begin
        rptr <= 0;
        rempty <= 1;
    end else begin
        if (rinc & ~rempty) begin
            rptr <= rptr + 1;
        end
        rempty <= rempty_wire;
    end
end

assign wbin = wptr[ADDR_WIDTH-1:0];
assign wgray = {wbin[ADDR_WIDTH-1], wbin[ADDR_WIDTH-1:1] ^ wbin[ADDR_WIDTH-2:0]};
assign rbin = rptr[ADDR_WIDTH-1:0];
assign rgray = {rbin[ADDR_WIDTH-1], rbin[ADDR_WIDTH-1:1] ^ rbin[ADDR_WIDTH-2:0]};

assign waddr = wbin;
assign raddr = rbin;

always @(posedge rclk or negedge rrstn) begin
    if (~rrstn) begin
        rdata <= 0;
    end else begin
        rdata <= rdata_wire;
    end
end

assign wfull_wire = (wgray == (rgray + 1)) && wptr[ADDR_WIDTH] != rptr_sync[ADDR_WIDTH];
assign rempty_wire = (wgray == rgray) && wptr_sync[ADDR_WIDTH] == rptr_sync[ADDR_WIDTH];

endmodule
